const CLIPBOARD_MESSAGE_ERROR = 'Error writing to clipboard';

/** @param {string} text */
const writeToClipBoard = async (text) => {
  // A prompt will ask for permissions if they weren't previously granted
  try {
    await navigator.clipboard.writeText(text);
    return text;
  } catch {
    try {
      const input = document.createElement('input');
      input.setAttribute('type', 'hidden');
      document.body.appendChild(input);
      input.value = text;

      input.focus();
      input.select();

      document.execCommand('copy');

      input.remove();

      return text;
    } catch {
      throw new Error(CLIPBOARD_MESSAGE_ERROR);
    }
  }
};

export default writeToClipBoard;
